// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 32

int F(int ***A, int dx, int dy, int dz, int size) {
    int *B = (int *)malloc(size * size * size * sizeof(int));
    int index = 0;
    for (int i = dx; i < dx + size; i++) {
        for (int j = dy; j < dy + size; j++) {
            for (int k = dz; k < dz + size; k++) {
                B[index++] = A[i][j][k];
            }
        }
    }
    int result = 1;
    for (int i = 1; i < size * size * size; i++) {
        if (B[i] != B[0]) {
            result = 0;
            break;
        }
    }
    if (result == 1) {
        free(B);
        return 1;
    }
    result = 0;
    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 2; j++) {
            for (int k = 0; k < 2; k++) {
                result += F(A, dx + i * size / 2, dy + j * size / 2, dz + k * size / 2, size / 2);
            }
        }
    }
    free(B);
    return result;
}

int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    int ***A = (int ***)malloc(N * sizeof(int **));
    for (int i = 0; i < N; i++) {
        A[i] = (int **)malloc(N * sizeof(int *));
        for (int j = 0; j < N; j++) {
            A[i][j] = (int *)malloc(N * sizeof(int));
        }
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            for (int k = 0; k < N; k++) {
                scanf("%d", &A[i][j][k]);
            }
        }
    }
    int min = F(A, 0, 0, 0, N);
    int max = F(A, 0, 0, 0, N);
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            for (int k = 0; k < N; k++) {
                for (int l = 0; l <= K; l++) {
                    int ***D = (int ***)malloc(N * sizeof(int **));
                    for (int x = 0; x < N; x++) {
                        D[x] = (int **)malloc(N * sizeof(int *));
                        for (int y = 0; y < N; y++) {
                            D[x][y] = (int *)malloc(N * sizeof(int));
                        }
                    }
                    for (int x = 0; x < N; x++) {
                        for (int y = 0; y < N; y++) {
                            for (int z = 0; z < N; z++) {
                                D[x][y][z] = A[x][y][z];
                            }
                        }
                    }
                    D[i][j][k] = 1 - D[i][j][k];
                    int temp = F(D, 0, 0, 0, N);
                    if (temp < min) {
                        min = temp;
                    }
                    if (temp > max) {
                        max = temp;
                    }
                    for (int x = 0; x < N; x++) {
                        for (int y = 0; y < N; y++) {
                            free(D[x][y]);
                        }
                        free(D[x]);
                    }
                    free(D);
                }
            }
        }
    }
    printf("%d %d\n", min, max);
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            free(A[i][j]);
        }
        free(A[i]);
    }
    free(A);
    return 0;
}

