    if (result == 1) {
        return 1;
    }
    result = 0;
    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 2; j++) {
            for (int k = 0; k < 2; k++) {
                result += F(A, dx + i * size / 2, dy + j * size / 2, dz + k * size / 2, size / 2);
            }
        }
    }
    return result;
}

